"""
MKT Context Commentary — Revelation chapters 17–20
Run: python3 scripts/zc-context-revelation-17-20.py

Source data used:
- data/interlinear/revelation.json
- data/translation/draft/mediating/revelation.json (MKT text)

Key decisions in this range:
- Babylon = Rome: treated as an established first-century cipher familiar to Jewish-Christian
  readers from 4 Ezra, 2 Baruch, Sibylline Oracles, and 1 Peter 5:13
- Seven kings (17:9-11): the "one who is" keeps the identification deliberately ambiguous;
  the Domitian-era dating is noted but the text's polyvalence is preserved
- Nero redivivus: the "beast that was and is not" reflects a real first-century expectation
  documented in Sib. Or. 4:119-124; 5:28-34, 137-154, 214-227
- The luxury goods list (18:12-13): treated as a realistic inventory of Roman imports, with
  geographic sourcing noted; slaves listed last to emphasize the economy's dehumanizing base
- Hallelujah (19:1): first occurrence in NT; drawn from the Egyptian Hallel (Ps 113-118)
- Gog and Magog (20:8): treated as eschatological cipher from Ezek 38-39, not literal nations
- Millennium (20:1-6): Second Temple parallels noted (4 Ezra 7:28-30; 2 Baruch 40:3)
  without prescribing a millennial position; the context layer is descriptive, not dogmatic
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

REVELATION = {
  "17": {
    "1": '<p>\'The great prostitute who sits by many waters\' introduces an allegory drawing on the OT prophetic tradition of characterizing pagan cities as promiscuous women who seduce the nations into spiritual unfaithfulness: Nineveh (Nah 3:4), Tyre (Isa 23:17), and above all Babylon (Isa 21:9; Jer 50-51). By the late first century CE, \'Babylon\' had become an established cipher for Rome in Jewish and early Christian literature. The Sibylline Oracles, 4 Ezra (3:1-2, 28-31), 2 Baruch (10:1-3; 11:1), and 1 Peter 5:13 all use Babylon as a code for Rome — an audience in the seven cities of Asia would recognize the identification immediately without John stating it explicitly.</p>',
    "2": '<p>\'All the nations have drunk the maddening wine of her adulteries\' describes Rome\'s hegemonic cultural and economic influence across the Mediterranean world. In the OT prophetic tradition, \'adultery\' and \'prostitution\' describe spiritual unfaithfulness to YHWH — covenant betrayal through accommodation to foreign gods (Jer 3:1-10; Ezek 16; Hos 1-3). Applied to Rome\'s client nations, the image captures the way Roman imperial ideology, cult, and commerce penetrated every dimension of subject-peoples\' lives. The \'wine\' of intoxication: those who profited from the imperial system became drunk on its benefits, unable to see its corrupting nature.</p>',
    "3": '<p>The \'scarlet beast covered with blasphemous names\' on which the woman rides is the same beast as in Revelation 13 — the Roman imperial power. The seven heads and ten horns identify it with the beast from the sea (13:1). The wilderness setting for the vision (\'carried me away in the Spirit into a wilderness\') echoes the wilderness as the place of prophetic encounter (Ezek 3:22; cf. the desert as the place of theophany). In the Exodus tradition, the wilderness was also the place where Israel encountered both God and the temptation to return to Egypt — the wilderness vision of Rome\'s doom mirrors the wilderness encounters of the prophets who spoke against Babylon and Egypt.</p>',
    "4": '<p>Purple and scarlet were the colors of Roman imperial and senatorial dress. The senatorial toga had a broad purple stripe; military commanders wore the paludamentum (a scarlet military cloak); and the emperor himself wore purple robes. In Revelation\'s audience cities, purple cloth was a luxury trade good (Lydia of Thyatira sold it in Philippi, Acts 16:14). The golden cup filled with \'abominations and the filth of her adulteries\' inverts the golden vessels of the Jerusalem temple — Belshazzar\'s use of temple vessels to toast his gods (Dan 5:1-4) is the type of this inversion: desacralizing the holy by using sacred vessels for profane purposes.</p>',
    "5": '<p>The \'mystery name\' on the woman\'s forehead echoes the practice of Roman prostitutes displaying their names on their foreheads (Seneca, <em>Controversiae</em> 1.2.7), while simultaneously employing the apocalyptic convention of revealed names as ciphers (Dan 4:19-27). \'Babylon the Great\' was recognizable as Rome: the Sibylline Oracles use it repeatedly (Sib. Or. 5:143, 158-161, 434); 4 Ezra 3:1-2 opens with the author claiming to be in \'Babylon\' (= Rome). \'Mother of Prostitutes and of the Abominations of the Earth\' echoes Nahum\'s characterization of Nineveh as a prostitute whose witchcraft enslaved nations (Nah 3:4) — Rome as the newest iteration of this historical pattern.</p>',
    "6": '<p>\'Drunk with the blood of God\'s holy people and the blood of those who bore testimony to Jesus\' refers to the Roman persecutions. The Neronian persecution of 64 CE is the most documented: after the fire of Rome, Nero blamed Christians and subjected them to elaborate public executions (Tacitus, <em>Annales</em> 15.44 — burned alive as human torches, thrown to wild animals, crucified). The apostles Peter and Paul were executed in Rome during this period. The Domitianic persecution (81-96 CE) — the probable period of Revelation\'s composition — targeted members of the Roman household who converted (Flavia Domitilla, exiled; Flavius Clemens, executed). John\'s astonishment (\'I was greatly astonished\') captures the psychological shock of seeing Rome\'s immense power revealed as a drunk murderess.</p>',
    "7": '<p>The angel\'s offer to explain the mystery is the standard apocalyptic interpretation scene: Daniel receives interpretations from Gabriel (Dan 7:15-16; 8:15-19); the angels of 1 Enoch explain heavenly visions to Enoch. The pattern establishes the apocalyptic seer as a mediator who receives not just visions but their authoritative interpretation — the reader receives the same explanation the seer did, making the community participants in the disclosure.</p>',
    "8": '<p>The \'beast that once was, now is not, and yet will come up out of the Abyss\' parodies the divine self-description (\'who was and is and is to come,\' 1:4, 4:8) while encoding the Nero redivivus legend. After Nero\'s suicide in 68 CE, a widespread belief emerged (documented in the Sibylline Oracles: 4:119-124; 5:28-34, 137-154, 214-227, 361-383) that he had fled to Parthia and would return at the head of a Parthian army. Three imposters claiming to be Nero appeared in 69, 80, and c. 88 CE. This expectation gave urgency to the \'once was, now is not, will come\' formula — a historical cipher for the anticipated return of the persecutor. The community \'whose name was not written in the book of life\' is embedded in the imperial order, astonished at Rome\'s apparent permanence.</p>',
    "10": '<p>\'Five have fallen, one is, and the other has not yet come\' refers to the sequence of Roman emperors. The precise identification depends on which emperor one begins counting from. Beginning with Augustus (27 BCE – 14 CE): Augustus (1), Tiberius (2), Caligula (3), Claudius (4), Nero (5) — five fallen; Vespasian (6) — one is; Titus (7) — not yet come; Domitian (8) — the eighth (v. 11). This count fits a composition date of 69-79 CE. Starting with Caligula or Julius Caesar produces different results. The text\'s deliberate ambiguity may be intentional — the formula applies to any moment in the empire\'s history when five are past and the end is near.</p>',
    "11": '<p>\'The beast who once was and now is not is an eighth king. He belongs to the seven and is going to his destruction.\' The eighth who \'belongs to the seven\' reflects the Nero redivivus expectation: Nero was the fifth emperor in one count; when he returns from Parthia (in the legend) he becomes a new figure who is simultaneously one of the original seven. The \'going to his destruction\' (<em>eis apōleian</em>) is the same destination as the false prophet and the beast (19:20; 20:10) — eternal judgment, not renewed power. The Nero redivivus myth that frightened the seven cities is met with the assurance that the returning tyrant is already heading to destruction.</p>',
    "12": '<p>The \'ten kings who have not yet received a kingdom\' are the Parthian satellite kings or military commanders who, in the Nero redivivus scenario, would provide the returning Nero with his army. The Roman fear of Parthia was real: Rome had suffered a catastrophic defeat at Carrhae (53 BCE) in which the general Crassus was killed and the legionary standards captured; Augustus had to negotiate their return diplomatically. The Euphrates as the boundary between Rome and Parthia (16:12) was the empire\'s most vulnerable frontier. The \'one hour\' of their authority captures the brevity and provisional nature of their power — granted only for the purpose of God\'s judgment.</p>',
    "13": '<p>The unity of purpose among the beast\'s allies (\'they have one purpose\') contrasts with Rome\'s historical pattern of factional conflict — the Year of Four Emperors (69 CE), the civil wars, the Praetorian Guard\'s repeated selling of the imperial throne to the highest bidder. The ironically unified purpose of the beast\'s coalition is to wage war against the Lamb — and this very unity is the mechanism of their defeat, since God has put it into their hearts to accomplish his purpose (v. 17).</p>',
    "14": '<p>\'They will wage war against the Lamb, but the Lamb will triumph\' — the victory formula uses \'Lord of lords and King of kings,\' titles with a specific ancient Near Eastern background. The Persian king was called \'king of kings\' (<em>melek malkayya</em>, Ezra 7:12; Ezek 26:7; Dan 2:37) — a claim to universal sovereignty over all other rulers. Antiochus IV Epiphanes used the title; Roman emperors claimed equivalent lordship. The Lamb\'s identification as \'Lord of lords and King of kings\' is the ultimate counter-claim: all the king-of-kings claims of history find their true referent only in him.</p>',
    "15": '<p>\'The waters you saw, where the prostitute sits, are peoples, multitudes, nations, and languages.\' Rome\'s power rested on its ability to integrate diverse ethnic and linguistic populations into the imperial order. The city of Rome itself was home to significant populations from across the Mediterranean world: Greek-speakers from the East formed a substantial community (early Roman Christianity was largely Greek-speaking), and Jews, Syrians, Egyptians, and North Africans all had significant communities in the capital. The \'many waters\' is thus a geopolitically accurate description of Rome\'s cosmopolitan subject peoples.</p>',
    "16": '<p>The beast and ten horns turning on the prostitute to \'bring her to ruin and leave her naked; they will eat her flesh and burn her with fire\' draws on the OT judgment formula applied to idolatrous women (Ezek 16:37-41; 23:25-29). Rome\'s actual history of civil war, assassination, and factional violence lent credibility to this scenario: the Year of Four Emperors (69 CE), the assassination of Caligula (41 CE), Domitian himself (96 CE), and the Praetorian Guard\'s repeated violent regime changes all demonstrated that the imperial power was internally self-destructive. Empires that live by violence tend to destroy themselves by violence.</p>',
    "17": '<p>\'God has put it into their hearts to accomplish his purpose by agreeing to hand over their royal authority to the beast until God\'s words are fulfilled.\' A recurring theological principle in Revelation: even the hostile powers act within the permission and purpose of God. The parallel is to Isa 10:5-7 (Assyria as God\'s rod of judgment against Israel, though Assyria does not intend this) and Jer 25:9 (Nebuchadnezzar called God\'s servant for the purpose of judgment). The apocalyptic framework does not portray history as an even contest between God and evil but as God\'s sovereign use of even evil\'s self-destructive tendencies for his own purposes.</p>',
    "18": '<p>\'The woman you saw is the great city that rules over the kings of the earth.\' The explicit identification of the woman with the city removes any lingering ambiguity: this is Rome, the city that in John\'s era unambiguously \'ruled the kings of the earth.\' The seven hills (v. 9), the scarlet imperial dress (v. 4), and the blood of martyrs (v. 6) all point to the same identification. The cipher of Babylon allowed Jews and Christians to speak of Rome\'s political reality in language legible to insiders but opaque to hostile authorities — a standard feature of apocalyptic literature from Daniel (written under Antiochus IV) through the Sibylline Oracles (written under various empires).</p>'
  },
  "18": {
    "1": '<p>The angel \'with great authority\' who illuminates the earth with his glory echoes the divine glory (<em>kābôd</em>) that filled the temple in Ezek 43:2 (\'the land shone with his glory\') and Isa 60:1-3 (\'Arise, shine, for your light has come, and the glory of the LORD rises upon you\'). The heavenly messenger\'s appearance with glory anticipates Rome\'s doom: the city that claimed to be \'eternal\' and that had eclipsed all other cities in grandeur is about to be eclipsed by the glory of the one God who holds all history.</p>',
    "2": '<p>\'Fallen! Fallen is Babylon the Great!\' quotes Isa 21:9 directly (\'Fallen, fallen is Babylon, and all the images of its gods lie shattered on the ground\'), the oracle of doom against the historical Babylon. The application of this Isaianic oracle to Rome follows the established Jewish literary practice of applying OT doom-texts to successive empires (Babylon → Persia → Greece → Rome). \'A dwelling place for demons, a haunt for every impure spirit\' draws on Isa 13:21-22 (Babylon\'s ruins become the haunt of desert creatures and jackals) and Isa 34:11-15 (Edom\'s ruins as the home of unclean animals). The desolation of cities that opposed God is a consistent OT motif.</p>',
    "3": '<p>\'The wine of Babylon\'s fornication\' draws on Jer 51:7 (\'Babylon was a golden cup in the LORD\'s hand; she made the whole earth drunk. The nations drank her wine; therefore they have now gone mad\'). Rome\'s commercial empire had made the world economically dependent: Paul\'s contemporaries in Corinth traded with Rome; merchants in Ephesus profited from the Roman peace; governors across the empire enriched themselves through Roman provincial administration. The \'kings\' and \'merchants\' who \'committed adultery with her\' are the political and commercial elite who built their prosperity on Rome\'s hegemony.</p>',
    "4": '<p>\'Come out of her, my people, so that you will not share in her sins\' draws directly on Jer 51:45 (\'Come out of her, my people! Run for your lives! Run from the fierce anger of the LORD\') and Isa 48:20 (\'Leave Babylon, flee from the Babylonians!\'). The call to separation from the condemned city reflects a recurring OT pattern: the faithful minority called out of Sodom (Gen 19:12-14), out of Egypt (Exod), out of Babylon (Isa 48; Jer 51). In the seven cities of Asia, this \'coming out\' was not geographic but social and economic — withdrawing from the trade guilds, the temple festivals, the civic religious life that embedded believers in the imperial system.</p>',
    "5": '<p>\'Her sins are piled up to heaven, and God has remembered her crimes.\' The \'pile up to heaven\' language echoes Gen 18:20-21 (the outcry of Sodom reaching heaven) and Jer 51:9 (Babylon\'s punishment extending to the skies). The divine \'remembering\' of crimes is a judicial concept in OT thought: God does not forget injustice (Ps 9:12; Jer 14:10; Hos 8:13; 9:9); the delay of judgment is patience, not forgetfulness. For communities that had watched Roman authorities execute their fellow believers without apparent consequence, the assurance that God had \'remembered\' Rome\'s crimes was a significant comfort.</p>',
    "6": '<p>\'Repay her double for what she has done\' — the lex talionis applied to Babylon in Jer 50:15, 29 (\'Do to her as she has done to others\') and in Isa 40:2 (Jerusalem has received \'double for all her sins\'); here applied to Rome. The doubling formula appears in several prophetic judgments (Jer 16:18; 17:18; Zech 9:12). The \'double cup\' she is to be given mirrors the cup she gave to the nations (14:10; 17:4): the same instrument of Rome\'s power over the world becomes the instrument of God\'s judgment against Rome.</p>',
    "7": '<p>\'In her heart she boasts, I sit enthroned as queen; I am not a widow; I will never mourn.\' Roman imperial propaganda presented Rome as eternal — <em>Roma Aeterna</em> (Eternal Rome) was a common phrase on coins, inscriptions, and in poets (Virgil, Ovid, Horace) who celebrated Rome\'s permanence. The personification of Rome as the goddess Roma, enthroned and triumphant, appeared on coins throughout the empire. The boast \'I am not a widow\' inverts the dirge of Lam 1:1 (\'She who was queen among the provinces has now become a slave\') — Rome claims the anti-widow status that the prophet had lamented over Jerusalem. The reversal: Rome will become what it inflicted on Jerusalem.</p>',
    "8": '<p>\'In one day her plagues will overtake her: death, mourning, and famine. She will be consumed by fire.\' The \'one day\' of judgment contrasts with the centuries of Rome\'s power — divine judgment is instantaneous against what seemed permanent. The judgment-by-fire echoes the destruction of Sodom (Gen 19:24-25) and the OT oracles against Babylon (Isa 13:19; Jer 50:32, 40; 51:30, 58). The earthquake that devastated several of the seven cities (Laodicea 60 CE; Philadelphia and Sardis 17 CE) would have made the scenario of sudden catastrophic destruction viscerally real to Revelation\'s audience — they had lived through cities leveled in moments.</p>',
    "9": '<p>The threefold mourning scene — kings, merchants, sea captains (vv. 9-10, 11-17, 17-19) — echoes Ezekiel\'s extended lament over the fall of Tyre (Ezek 27), which describes the mourning of Tyre\'s trading partners at her destruction. Ezekiel 27 lists the same categories: kings of the coastlands (27:35), merchants (27:36), and sailors (27:29). Tyre was the commercial metropolis of its era; Rome had become the commercial metropolis of the first century CE; the lament formula transfers from Tyre to Rome as the next commercial empire. The kings who \'committed adultery with her\' are the client kings whose relationship with Rome had made them wealthy.</p>',
    "10": '<p>\'Terrified at her torment, they will stand far off\' — the distance of the mourners (three times repeated: vv. 10, 15, 17) is not simply grief but self-protective separation: they do not want to be caught in Rome\'s judgment. In the Roman commercial world, Rome\'s destruction would have been an economic catastrophe for its trading partners — Corinth was rebuilt by Caesar specifically because of its commercial importance; Ephesus\'s prosperity was tied to Roman trade. The terror is the recognition that the system that produced one\'s wealth has collapsed.</p>',
    "11": '<p>The merchants\' weeping (\'because no one buys their cargo anymore\') captures the economic dimension of Rome\'s dominance. Rome imported vast quantities of luxury goods from across the known world, financed by wealth extracted from conquered territories and managed through the Roman monetary system. Merchants from the seven cities of Asia — Ephesus was the main port of entry for Asian goods going to Rome — were deeply embedded in this trade network. The cessation of Roman trade would have meant the collapse of the economic basis of life in the major Asian cities. The merchants\' tears are economically grounded grief, not mere sentiment.</p>',
    "12": '<p>The luxury goods inventory of vv. 12-13 is a realistic list of Roman imports documented in ancient sources (particularly Pliny\'s <em>Natural History</em> 6 and 12). Gold and silver came from mines in Spain, Dacia, and Britain. Precious stones: diamonds (India), emeralds (Egypt), rubies and sapphires (India and Ceylon). Pearls: the Persian Gulf via Alexandria — Pliny (<em>NH</em> 37.14) estimated Rome spent 100 million sesterces per year on Eastern luxuries. Fine linen: Egyptian linen from the Nile delta. Purple cloth (Tyrian purple): produced from Murex snails along the Phoenician coast and at Thyatira — the most expensive dye in antiquity. Silk: imported from China via the Silk Road through Parthia, worth its weight in gold in Rome.</p>',
    "13": '<p>The commodity list continues: cinnamon from Sri Lanka (transported via southern Arabia); spice (<em>amōmon</em>) from India; incense from southern Arabia; myrrh from Somalia and Arabia; frankincense from Dhofar (modern Oman). These aromatic commodities traveled via the Indian Ocean trade routes, making them enormously expensive by the time they reached Rome. The list concludes with \'slaves and human souls\' — the most brutal notation, placed last for rhetorical emphasis. Rome\'s economy was fundamentally slave-based: the scholar Keith Hopkins estimated that Rome had 2-3 million slaves in Italy alone during the imperial period. The conjunction of luxury goods and human beings as tradeable commodities exposes the moral foundation of the imperial economic system.</p>',
    "14": '<p>\'The fruit you longed for is gone from you\' — the \'fruit\' (<em>opōra</em>) specifically refers to ripe autumn fruit, the season of abundance. In the agricultural imagery that pervades the ancient world, the loss of the autumn harvest was synonymous with the loss of all prosperity. The \'luxury and splendor\' that \'have vanished, never to be recovered\' captures the permanent character of the judgment: not a temporary setback but the complete end of the system that produced Roman luxury.</p>',
    "15": '<p>The merchants \'who sold these things and gained their wealth from her\' replicate the self-protective distancing of the kings (v. 10): \'they will stand far off, terrified at her torment.\' In Roman commercial practice, merchants from the provinces (including Asia Minor) maintained agents and trading relationships with Roman buyers. The commercial network that made Ephesus and Smyrna prosperous was ultimately dependent on Rome\'s insatiable appetite for luxury imports. The collapse of Rome\'s purchasing power would have been an existential threat to the commercial economies of the Asian cities.</p>',
    "16": '<p>The triple woe-formula (\'woe, woe\') is the dirge meter (<em>qînāh</em>) of OT lament poetry — Amos 5:1 uses the same meter for Israel\'s funeral song; Lamentations employs it throughout for Jerusalem. The merchants\' lament over Rome\'s \'fine linen, purple and scarlet, glittering with gold, precious stones, and pearls\' precisely echoes the description of the prostitute Babylon in 17:4. They mourn not an innocent victim but the source of their own enrichment — their grief is for their own economic loss, not for Rome\'s victims.</p>',
    "17": '<p>\'Every sea captain, and all who travel by ship, the sailors, and all who earn their living from the sea, will stand far off.\' Rome\'s trade was overwhelmingly seaborne: the port of Ostia at the mouth of the Tiber was Rome\'s main commercial harbor, and a network of ports (Puteoli on the Bay of Naples, Brundisium on the Adriatic, Alexandria in Egypt) sustained the imperial trade network. The \'standing far off\' of the sea captains recalls Ezek 27:29-30 (\'All the sailors, the mariners and all the pilots of the sea... will stand on the shore and wail bitterly\' over Tyre\'s destruction).</p>',
    "18": '<p>\'Was there ever a city like this great city?\' — the sailors\' rhetorical question captures the unique character of Rome as an urban phenomenon in the ancient world. Rome\'s population at its peak (late first to second century CE) was perhaps 800,000 to 1 million people — an order of magnitude larger than most ancient cities. Its public buildings (the Colosseum, begun under Vespasian; the Pantheon; the Forum of Trajan), its aqueducts, and its urban amenities were without parallel in the ancient world. The smoke of its burning would be visible from the sea — Smyrna, Carthage, Jerusalem had all burned in living memory of the first audience.</p>',
    "19": '<p>\'Throwing dust on their heads\' is a mourning gesture documented throughout the ancient Near East: Joshua 7:6 (Israel mourning defeat at Ai); Job 2:12 (Job\'s friends responding to his suffering); Lam 2:10 (Zion\'s elders sitting in dust); Ezek 27:30 (the sailors mourning Tyre). The gesture expresses grief that surpasses words — the body enacts the diminishment that the soul feels. The sailors\' weeping and mourning over their own economic loss (\'by which they became wealthy\') continues the pattern of self-interested grief: Rome\'s mourners grieve their own losses, not Rome\'s victims.</p>',
    "20": '<p>\'Rejoice over her, you heavens! Rejoice, you people of God and apostles and prophets!\' draws on Isa 44:23 (\'burst into song, you mountains, you forests and all your trees, for the LORD has redeemed Jacob\') and Jer 51:48 (\'Then heaven and earth and all that is in them will shout for joy over Babylon\'). The rejoicing is not cruelty but the vindication of justice — the recognition that God\'s judgment of oppression is itself good news for the oppressed. \'God has judged her with the judgment she imposed on you\' is the lex talionis applied: what Rome did to the martyrs, God has done to Rome.</p>',
    "21": '<p>The mighty angel throwing a millstone into the sea enacts Jer 51:63-64, where the prophet Seraiah was commanded to tie a stone to the scroll containing the doom oracle against Babylon and throw it into the Euphrates, saying \'So will Babylon sink to rise no more.\' The millstone was the largest common heavy object in the ancient world — used in grain mills, rotated by animals or slaves, sometimes used as a weapon (Judg 9:53: Abimelech killed by a millstone dropped from a tower). Its sinking represents the total, permanent, irreversible character of Rome\'s judgment: not a setback but obliteration.</p>',
    "22": '<p>The catalog of silences (\'the music of harpists... will never be heard in you again... no craftsman of any trade will ever be found in you again... the sound of a millstone will never be heard in you again\') echoes Jer 25:10 and Jer 7:34 — the oracle against Jerusalem that silenced the voice of bride and groom, the sound of grinding, and the light of the lamp. The same judgment-silences are transferred from Jerusalem to Rome: what God did to his unfaithful covenant city (Jerusalem, under Nebuchadnezzar) he will do to the unfaithful imperial city (Rome). The millstone\'s silence echoes the millstone thrown into the sea in v. 21 — the instrument of daily bread is stilled in the dead city.</p>',
    "23": '<p>\'The light of a lamp will never shine in you again. The voices of bride and groom will never be heard in you again.\' The light of the lamp was the basic sign of human habitation — households in the ancient world were lit by oil lamps, and a dark city was a dead city. The \'voices of bride and groom\' — the wedding celebration that was the highest point of community social life — is the final silence of communal joy. Jer 25:10 had applied this same silence to Jerusalem under Babylonian destruction. The identification of Rome\'s \'merchants\' as \'the world\'s important people\' names the economic elite whose complicity in Rome\'s system is their indictment.</p>',
    "24": '<p>The climactic indictment — \'In her was found the blood of prophets and of God\'s holy people, of all who have been slaughtered on the earth\' — grounds the entire doom oracle in the specific sin of persecution. Jesus had applied similar language to Jerusalem (Matt 23:35-37: \'all the righteous blood shed on earth\'); the prophets had applied it to Babylon (Jer 51:35, 49). Now Rome is the city that has accumulated in herself the blood of all who died for faithful witness. This is not merely an accusation but a legal indictment: blood guilt attaches to the city, and the sentence is its destruction.</p>'
  },
  "19": {
    "1": '<p>\'Hallelujah\' (<em>hallēlouia</em> = Hebrew <em>hallĕlû-Yāh</em>, \'praise Yah\') occurs four times in Revelation 19 (vv. 1, 3, 4, 6) — its only occurrences in the NT. The word comes from the Hebrew Psalter; the \'Egyptian Hallel\' (Ps 113-118) was the liturgical unit sung at Passover (the Seder), at Pentecost (Shavuot), Tabernacles (Sukkot), and the Feast of Dedication (Hanukkah). Jesus and his disciples sang a hymn (likely from the Hallel) at the Last Supper before going to Gethsemane (Matt 26:30; Mark 14:26). The Hallelujah that opens the heavenly liturgy after Babylon\'s fall is the Passover shout of praise for a new exodus — redemption from a new Egypt/Babylon/Rome.</p>',
    "2": '<p>\'His judgments are true and just\' echoes the liturgical affirmation of Ps 19:9 (\'The decrees of the LORD are sure; they are righteous altogether\') and Ps 119:137, 142. The heavenly court affirms the justice of the judgment before stating the crime: the great prostitute \'corrupted the earth with her adulteries\' (the economic and spiritual dimension of Roman hegemony) and God \'has avenged on her the blood of his servants\' (the specific persecution of believers). The two-part indictment (general corruption + specific violence) mirrors the OT legal pattern of naming both systemic injustice and specific crimes.</p>',
    "3": '<p>\'The smoke from her goes up forever and ever.\' This echoes the divine judgment on Edom in Isa 34:10 (\'The smoke from Edom will rise forever; from generation to generation it will lie desolate\'). In the OT tradition, Edom was the perpetual enemy — the nation that celebrated Jerusalem\'s fall (Ps 137:7; Lam 4:21-22; Obadiah). The permanence of the smoke represents the irreversibility of divine judgment: unlike the cities Rome destroyed and rebuilt (Jerusalem was rebuilt as Aelia Capitolina; Carthage rebuilt as a Roman colony), this destruction has no second act.</p>',
    "4": '<p>The twenty-four elders and four living creatures falling down and worshipping God echoes and closes the throne-room vision of chs. 4-5. Their \'Amen, Hallelujah!\' ratifies the heavenly choir\'s praise with the liturgical sealing formula. \'Amen\' is the assembly\'s confirmation that the words spoken are true and binding (Israel used \'Amen\' in Deut 27:15-26 to confirm the covenant curses; Paul describes it as the appropriate congregational response to prayer and praise in 1 Cor 14:16). The combination of Amen and Hallelujah frames the divine judgment with the fullness of the covenant community\'s worship.</p>',
    "5": '<p>A \'voice from the throne\' — not God directly, but the divine voice mediated through the throne context — issues the call to praise. The instruction to \'praise our God, all you his servants, you who fear him, both great and small\' echoes Ps 135:1 (\'Praise the name of the LORD; praise him, you servants of the LORD\') and Ps 115:13 (\'he will bless those who fear the LORD — small and great alike\'). The democratization of praise (\'great and small\') breaks down the social hierarchy that Rome had cultivated: in the Roman imperial system, the great praised and the small were ignored; in the divine order, both are called equally.</p>',
    "6": '<p>\'The roar of a great multitude, like the roar of rushing waters and like loud peals of thunder\' converges all three acoustic images from Revelation\'s throne-room (4:5: thunder; 1:15: many waters; 11:15: great voices) in one sound. The shout \'Hallelujah! For our Lord God Almighty reigns\' (<em>ebasileusev</em> — aorist: the decisive moment of enthronement) announces not just that God reigns eternally (always true) but that his reign has now been decisively manifested in history through the judgment of Babylon.</p>',
    "7": '<p>\'The wedding of the Lamb has come, and his bride has made herself ready.\' The wedding banquet as the image of the messianic era has deep roots in Jewish eschatological tradition: Isa 25:6-8 (the LORD of hosts makes a feast of rich food for all peoples on Mount Zion); 2 Baruch 74:1 (the era of the Messiah is a time of joy); 1 Enoch 62:14 (the righteous feast and rest with the Son of Man). The parables of the ten virgins (Matt 25:1-13) and the wedding banquet (Matt 22:1-14) had made the wedding image central to Jesus\'s teaching. The bride \'has made herself ready\' — the active preparation contrasts with Babylon\'s passive self-indulgence.</p>',
    "8": '<p>\'Fine linen, bright and clean, was given to her to wear — for the fine linen stands for the righteous acts of God\'s holy people.\' The deliberate contrast with the prostitute\'s purple and scarlet (17:4; 18:16) uses the symbolism of clothing as a moral status indicator. White linen was the material of the priestly vestments (Exod 28:39; Lev 16:4); Zechariah\'s vision of Joshua the high priest being reclothed in clean garments (Zech 3:3-5) is the prototype. The linen is \'given to her\' — it is a gift, not an achievement; yet it represents \'the righteous acts\' of the saints — both grace and faithfulness are affirmed simultaneously.</p>',
    "9": '<p>The fourth of Revelation\'s seven beatitudes: \'Blessed are those who are invited to the wedding supper of the Lamb!\' The parallel with the parable tradition (Matt 22:1-14; Luke 14:15-24) is direct: in both parables, the invitation to the messianic banquet is extended and rejected by those too absorbed in earthly affairs. The authentication formula \'These are the true words of God\' appears four times in Revelation (19:9; 21:5; 22:6) — each time marking a moment of supreme disclosure. It is the divine guarantee of the vision\'s reliability against the counter-claims of imperial propaganda.</p>',
    "10": '<p>John\'s prostration to worship the angel (and the angel\'s rebuke) reflects a real danger in the late first century: angel worship was practiced in some Jewish and Gnostic communities and appears as a concern in Col 2:18 and 2 Enoch 1:5-10 (Enoch falling before angels to worship them). The angel\'s refusal — \'Don\'t do that! I am a fellow servant with you\' — represents the monotheistic principle: only God receives worship. \'The testimony of Jesus is the spirit of prophecy\' is a compressed claim: the Holy Spirit who inspires prophecy and the testimony of Jesus are the same thing; the Spirit\'s work in the prophets is to bear witness to Jesus.</p>',
    "11": '<p>The \'heaven opened\' (<em>ēneōgmenon ton ouranon</em>) echoes the opened heaven at Jesus\'s baptism (Mark 1:10), at Stephen\'s martyrdom (Acts 7:56), and at Ezekiel\'s inaugural vision (Ezek 1:1). The white horse and its rider reverse the opening of the first seal (6:2: the rider on a white horse going out to conquer) — what appeared as a threat now appears as the divine warrior. The titles \'Faithful and True\' echo the letter to Laodicea (3:14: \'the Amen, the faithful and true witness\') — the same Christ who addressed the compromising church now appears as the cosmic judge. \'Judges and makes war with justice\' establishes the criterion: not arbitrary power but righteous adjudication.</p>',
    "12": '<p>\'Many crowns on his head\' — the Greek <em>diadēmata</em> (royal crowns, as worn by kings) rather than <em>stephanoi</em> (victor\'s wreaths, as given to athletes). Roman emperors wore the laurel wreath, not the diadem (the diadem was associated with Persian and Hellenistic kingship; Julius Caesar famously refused the diadem to avoid accusations of wanting to be a king). The many crowns represent sovereignty over all kingdoms — he holds what no emperor could claim. \'A name written that no one knows but he himself\' reflects the ancient conception that knowing a name gave power over its bearer — God\'s ultimate name is beyond human comprehension, and Christ participates in that mystery.</p>',
    "13": '<p>A robe \'dipped in blood\' before the battle draws on Isa 63:1-6 — the divine warrior returning from Edom whose robes are stained with the blood of his enemies: \'Why is your apparel red, and your garments like the one who treads in the winepress?\' In Isa 63 the figure treads the winepress of God\'s wrath alone, with no one to help. The blood on the robe is thus the blood of divine judgment executed against those who opposed God\'s people — the warrior arrives already clothed in the evidence of his judicial victory. The name \'The Word of God\' (<em>ho Logos tou Theou</em>) connects this figure to the Johannine Logos tradition (John 1:1) — the same creative word that called the universe into being executes its final judgment.</p>',
    "14": '<p>The armies of heaven following the Rider in white linen, unarmed, reflect the divine-warrior tradition in which God fights his own battles without human military assistance: the Exodus (God fought for Israel while Israel stood still, Exod 14:14); Gideon\'s 300 (the victory was divine, not military); Jehoshaphat (2 Chr 20:17). The armies wear the bride\'s linen (19:8) — they are the community of the faithful, following the Lamb. The absence of weapons in the heavenly army is deliberate: the decisive combat in Revelation is not military but judicial.</p>',
    "15": '<p>\'From his mouth comes a sharp sword to strike down the nations.\' The sword from the mouth is the word of divine judgment — the motif appears in Isa 11:4 (the messianic king will \'strike the earth with the rod of his mouth; with the breath of his lips he will slay the wicked\') and is consistent with Revelation\'s counter to Roman military power: the Lamb conquers not by the sword of the Roman legions but by the word of truth. \'He will rule them with an iron rod\' quotes Ps 2:9 — the messianic king\'s universal sovereignty. \'He treads the winepress of the fury of the wrath of God Almighty\' returns to Isa 63:1-6.</p>',
    "16": '<p>\'King of kings and Lord of lords\' is the climactic title, inscribed on the Rider\'s robe and thigh — visible to those behind him as he rides into battle. In Persian royal titulature, the king was \'great king, king of kings\' (<em>šar šarrāni</em>): Ezra 7:12 uses this title for Artaxerxes; Ezek 26:7 for Nebuchadnezzar. Antiochus IV took the title <em>Theos Epiphanes</em> (God Manifest). The Roman emperor claimed universal sovereignty through his titles. The inscription on the thigh recalls warriors and conquerors who wore their name or title on the pommel of their sword or the thigh of their riding garment — the place visible to those following them in procession.</p>',
    "17": '<p>The angel standing in the sun calling birds to \'the great supper of God\' is the anti-feast — the grotesque counterpart of the wedding supper of the Lamb (v. 9). It draws directly on Ezek 39:17-20 (God\'s invitation to the birds and wild animals to \'eat flesh and drink blood\' after the defeat of Gog and Magog). In the ancient Near Eastern and Greco-Roman tradition, burial was essential for the honor of the dead; to be left unburied and eaten by birds was the ultimate disgrace. Roman practice was to leave crucified bodies for the birds and dogs (Jewish precedent: Deut 21:22-23 required burial by nightfall). The great supper of God inverts this: those who persecuted are left for the birds.</p>',
    "18": '<p>The list of those eaten by birds — \'kings... commanders... mighty... horses... riders... all people, free and slave, great and small\' — recapitulates the social hierarchy of the Roman world. \'Free and slave\' names the fundamental Roman social division (the free person had legal standing; the slave was property). \'Great and small\' rejects the differential value the Roman system placed on persons according to social rank. The list makes clear that the beast\'s defeat is total across all social categories — no rank provides protection from divine judgment.</p>',
    "19": '<p>The beast and \'the kings of the earth with their armies gathered together to wage war against the Rider\' echoes the coalition against the Lamb in 17:14 and the Gog coalition of Ezek 38-39. The eschatological battle between God and the gathered nations is a motif that appears across Jewish apocalyptic literature (Joel 3:9-16; Zech 14:1-3; 1QM — the War Scroll from Qumran, which describes an eschatological war between the Sons of Light and the Sons of Darkness). The actual combat in Revelation 19 is noticeably absent — the beast is simply \'captured\' without a battle narrative. The point is not the drama of warfare but the absolute inevitability of divine victory.</p>',
    "20": '<p>The beast and false prophet are \'thrown alive into the lake of burning sulfur.\' The \'lake of fire\' as a place of eternal punishment appears in Jewish literature (1 Enoch 54:1-2: the valley of fire where fallen angels are punished; 4 Ezra 7:36: \'the furnace of Gehenna\'). Sulfur and fire appear in the judgment of Sodom and Gomorrah (Gen 19:24) and in Ezekiel\'s judgment against Gog (Ezek 38:22). The specific punishment \'thrown alive\' — without first being killed — emphasizes the irreversibility of the judgment: there is no death that precedes and mitigates the punishment.</p>',
    "21": '<p>\'The rest were killed by the sword that came from the mouth of the rider.\' The \'sword of the mouth\' — the word of divine judgment — kills what Roman legionary swords could not: the entire coalition gathered against God. The birds being \'gorged with their flesh\' is the literal fulfillment of the angel\'s invitation in v. 17 — the narrative completes what the oracle announced. The anti-feast imagery closes the arc opened by the Nicolaitan controversy of chs. 2-3: those who ate idol-food at Rome\'s banquets are now consumed at the great supper of God.</p>'
  },
  "20": {
    "1": '<p>\'The key to the Abyss and a great chain\' — the angel descending with these instruments echoes 9:1, where the key to the Abyss was given to the star-angel who released the demonic locusts. The \'Abyss\' (<em>abyssos</em>) is the primordial deep, the cosmic prison for demonic forces, corresponding to the Semitic <em>tehom</em> (the deep of Gen 1:2). In Jewish apocalyptic literature, fallen angels are imprisoned in the Abyss: 1 Enoch 10:4-6 describes Azazel bound \'under dark and jagged rocks\'; 1 Enoch 54:3-5 describes the angels of punishment preparing fetters for the host of Azazel; Jude 6 and 2 Pet 2:4 describe the angels who sinned bound in chains in the deepest darkness. The motif of cosmic imprisonment was part of the stock apocalyptic vocabulary.</p>',
    "2": '<p>The naming of the dragon as \'that ancient serpent who is the devil and Satan\' consolidates four identifications that the biblical and Second Temple traditions had associated with each other: (1) the serpent of Gen 3 (the agent of the fall); (2) the dragon of ancient Near Eastern creation mythology (Leviathan/Rahab/Tiamat); (3) the \'devil\' (<em>diabolos</em> = \'accuser\' or \'slanderer\'); and (4) \'Satan\' (the adversary of Job 1-2 and Zech 3:1-2). The consolidation was complete in Second Temple literature (Wis 2:24: \'through the devil\'s envy death entered the world\'; the Qumran scrolls connect the serpent and Belial). The thousand-year binding is the decisive curtailment of Satan\'s operative capacity.</p>',
    "3": '<p>The sealing of the Abyss over Satan \'so that he could no longer deceive the nations\' identifies deception as Satan\'s primary mode of operation — consistent with his title as the \'father of lies\' (John 8:44) and his role as the deceiver of the whole world (12:9). The nations that had been deceived into the imperial cult and the worship of the beast will be, for the thousand years, freed from this systematic deception. The \'little while\' of Satan\'s release after the thousand years frames the millennium not as the permanent final state but as a penultimate stage before the final resolution.</p>',
    "4": '<p>\'Thrones, and those seated on them were given authority to judge\' draws on Dan 7:9 (\'Thrones were set in place, and the Ancient of Days took his seat\') and Dan 7:22 (\'the time came when the holy people of the Messiah possessed the kingdom\'). The specific mention of \'those who had been beheaded\' is significant: beheading was the Roman method of execution for citizens of standing (crucifixion was for slaves and non-citizens). The martyrs who died by the specific Roman method of execution are the first to be enthroned. The refusal to worship \'the beast or its image\' — which in the Asian cities meant refusal to participate in the imperial cult — is the specific act of faithfulness that qualifies these martyrs for the thousand-year reign.</p>',
    "5": '<p>\'The rest of the dead did not come to life until the thousand years were ended. This is the first resurrection.\' The concept of a staged or sequential resurrection appears in Second Temple literature: 4 Ezra 7:28-30 describes a period of four hundred years in which the Messiah and survivors enjoy the transformed world, after which all die and the general resurrection follows; 2 Baruch 40:3 describes the Messiah\'s kingdom ending \'when the time of the world is fulfilled\'; 2 Enoch 33:1 describes a \'thousand years of rest\' after six thousand years of world history. These texts show that the concept of an interim messianic period before the final consummation was part of Jewish eschatological expectation by the first century.</p>',
    "6": '<p>The fifth of Revelation\'s seven beatitudes: \'Blessed and holy are those who share in the first resurrection.\' The specific promise that \'the second death has no power over them\' — the second death being the lake of fire (v. 14) — reverses the martyrs\' experience. Rome had power over the first death (the execution of believers) but no power over the second death (the eternal judgment); the martyrs\' willingness to face the first death rather than apostasy means that the second death has no jurisdiction over them. \'They will be priests of God and of Christ and will reign with him for a thousand years\' — the Exod 19:6 theme (a kingdom of priests) is given its eschatological actualization.</p>',
    "7": '<p>\'When the thousand years are over, Satan will be released from his prison.\' The release of Satan at the millennium\'s end is not an escape but a divine permission — the same sovereignty that bound him permits his release for the purpose of the final judgment. The pattern echoes God\'s use of evil for providential purposes (Isa 10:5-7: Assyria as God\'s instrument; Job 1-2: Satan permitted to test Job within set limits; Rev 17:17: God puts it into the beast\'s allies\' hearts to accomplish his purpose). The second and final defeat of Satan after his release will be more definitive than any binding — he goes not back to the Abyss but to the lake of fire (v. 10).</p>',
    "8": '<p>\'Gog and Magog\' in Revelation 20 transfers the Ezekiel 38-39 eschatological battle scenario to the period after the millennium. In Ezekiel, Gog of the land of Magog (a northern ruler identified variously with Gyges of Lydia or various Scythian peoples) leads a coalition against the restored Israel in the last days. By the first century CE, \'Gog and Magog\' had become eschatological ciphers for the final pagan coalition against God\'s people — an interpretation found in the Qumran pesharim and in later rabbinic tradition (b. Sanhedrin 97b; m. Eduyot 2:10). The \'four corners of the earth\' emphasizes the universal scope of the final rebellion: every nation, not just the Roman empire.</p>',
    "9": '<p>\'They marched across the breadth of the earth and surrounded the camp of God\'s people, the city he loves.\' \'The camp\' (<em>parembolē</em>) echoes the wilderness-period description of Israel as a traveling camp (Num 2; 10:11-36) — the eschatological people of God as the new wilderness camp. \'The city he loves\' is the eschatological Jerusalem, drawing on Ps 87:2 (\'the LORD loves the gates of Zion\'), Ps 78:68 (God chose Mount Zion \'which he loved\'), and Zech 1:17 (\'the LORD will again comfort Zion and choose Jerusalem\'). The siege of Jerusalem\'s eschatological counterpart is the final military expression of human opposition to divine sovereignty.</p>',
    "10": '<p>\'The devil who had deceived them was thrown into the lake of burning sulfur, where the beast and the false prophet had been thrown.\' The three figures who form the satanic parody of the Trinity (the dragon who empowers the beast, the beast who demands worship, the false prophet who enforces it — ch. 13) are all disposed of in the same lake of fire. \'Day and night forever and ever\' mirrors the smoke of Babylon going up \'forever and ever\' (19:3) — the permanence of divine judgment is as absolute as the permanence of divine praise. What claimed eternity receives eternal judgment.</p>',
    "11": '<p>The great white throne vision is the climax of Revelation\'s judicial imagery. The throne has been the central image since ch. 4; it has been described as the seat of God\'s holiness (4:2-3), the source of judgment (6:16-17), the location of the divine court (8:3-5). Now it becomes the specific instrument of final judgment. \'Earth and sky fled from his presence, and there was no place for them\' draws on Ps 114:3, 7 (the sea fled and the hills skipped); Isa 51:6 (\'the heavens will vanish like smoke, the earth will wear out like a garment\'); and 2 Pet 3:10-12 (the heavens dissolving with a roar, the elements melting). The dissolution of the current created order makes way for the new creation of 21:1.</p>',
    "12": '<p>\'Books were opened, and another book was opened, which is the book of life.\' The dual record-keeping of divine judgment appears in Dan 7:10 (\'the court was seated, and the books were opened\'); 1 Enoch 47:3 (\'the Head of Days sat and the books of the living were opened before him\'); and 4 Ezra 6:20 (\'the books are opened before the Judge\'). The distinction between \'books\' (records of deeds) and \'the book of life\' (the divine register of the redeemed, cf. 3:5; 13:8; 17:8) represents the two dimensions of divine judgment: deeds as evidence, grace as the criterion of ultimate salvation.</p>',
    "13": '<p>\'The sea gave up the dead that were in it, and Death and Hades gave up the dead that were in them.\' The universal resurrection encompasses all the dead regardless of where or how they died. \'The sea\' as a domain of the dead reflects ancient Near Eastern cosmology — the sea was the watery chaos from which the dead could not return (cf. Job 26:5-6: the dead tremble under the waters). The tripartite enumeration (sea, Death, Hades) ensures that no domain of death can withhold its dead from the final judgment. The universality of resurrection is the precondition for the universality of judgment.</p>',
    "14": '<p>\'Then Death and Hades were thrown into the lake of fire.\' The personification of Death and Hades as powers subject to divine disposal draws on the OT tradition of Death as a devouring power (Isa 5:14: Sheol opens its throat wide; Hab 2:5: death is never satisfied) and on 1 Cor 15:26 (\'the last enemy to be destroyed is death\'). The destruction of Death and Hades is the final act of the divine warrior: not just defeating Rome or the dragon but eliminating death itself as a cosmic power. The lake of fire receiving Death is the \'death of death\' — the irreversible end of the power that had dominated human existence since the fall.</p>',
    "15": '<p>\'Anyone whose name was not found written in the book of life was thrown into the lake of fire.\' The book of life as the criterion of salvation appears throughout Revelation (3:5; 13:8; 17:8; 20:12; 21:27). In Roman civic practice, citizens\' names were registered in civic rolls (<em>albi</em>); failure to be registered was social and legal non-existence. The eschatological book of life is the divine counterpart: to be \'written\' is to belong to the covenant community of the redeemed. The two books — of deeds and of life — together represent the full complexity of divine judgment: deeds reveal the truth of each life; the book of life records whom God has redeemed.</p>'
  }
}

def main():
    existing = load_comm('mkt-context', 'revelation')
    merge_comm(existing, REVELATION)
    save_comm('mkt-context', 'revelation', existing)

    il = json.loads((ROOT / 'data' / 'interlinear' / 'revelation.json').read_text())
    all_ok = True
    for ch in range(17, 21):
        ck = str(ch)
        il_vv = set(il.get(ck, {}).keys())
        out_vv = set(existing.get(ck, {}).keys())
        missing = sorted(il_vv - out_vv, key=int)
        if missing:
            print(f'  ch{ch}: MISSING {missing}')
            all_ok = False
        else:
            print(f'  ch{ch}: complete ({len(out_vv)} verses) ✓')
    if all_ok:
        print('  All chapters complete ✓')

if __name__ == '__main__':
    main()
